import { describe, expect, it } from 'vitest';

import {
  isThothNpcHalogramMetrics,
  renderThothNpcHalogramPromptContext,
  thothNpcHalogramMetricsFromSharedUiHalogram,
} from '../src/thoth-npc-halogram';

describe('Thoth NPC halogram adapter', () => {
  it('maps shared-ui Halogram summaries into bounded Thoth prompt metrics', () => {
    const metrics = thothNpcHalogramMetricsFromSharedUiHalogram({
      userId: 'user-best-self',
      displayName: 'North Star',
      calibratedConfidences: {
        layer1_temperament: 0.8,
        layer2_attachment: 0.7,
      },
      coherenceAssessment: {
        overallCoherence: 1.2,
        remainingTensions: ['overextension'],
      },
      biasCorrections: {
        biasesDetected: ['recency'],
        correctionsApplied: ['source-weighting', 'uncertainty'],
      },
      optimizedProfile: {
        growthAreas: ['boundary-setting'],
        blindSpots: ['urgency'],
        bestSelfDescription: 'Calm, precise, and available under pressure.',
      },
      voice: {
        tone: 'gentle',
        formality: 'casual',
        directness: -0.25,
        emotionality: 0.75,
      },
      body: {
        presentation: 'androgynous',
        build: 'athletic',
        gestureProfile: 'still-hands',
        presenceIntensity: 2,
      },
      meta: {
        dataQualityScore: 0.6,
        confidenceInProjection: 0.9,
      },
      aggregateMetacognition: {
        meta: {
          layersProcessed: 7,
          totalCorrectionsApplied: 3,
        },
      },
    });

    expect(isThothNpcHalogramMetrics(metrics)).toBe(true);
    expect(metrics.npcId).toBe('user-best-self');
    expect(metrics.voiceDirectness).toBe(0);
    expect(metrics.bodyPresenceIntensity).toBe(1);
    expect(metrics.overallCoherence).toBe(1);
    expect(metrics.calibratedConfidenceCount).toBe(2);
    expect(metrics.aggregateLayersProcessed).toBe(7);
    expect(metrics.aggregateCorrectionsApplied).toBe(3);
    expect(metrics.observationWithoutIntervention).toBe(true);
    expect(metrics.nonAuthoritative).toBe(true);
    expect(metrics.optimalSelfProjection).toBe(true);

    const prompt = renderThothNpcHalogramPromptContext(metrics);
    expect(prompt).toContain('kind=thoth.npc-halogram.v1');
    expect(prompt).toContain('voiceTone=gentle');
    expect(prompt).toContain('bodyPresentation=androgynous');
    expect(prompt).toContain(
      'bestSelf=Calm,_precise,_and_available_under_pressure.',
    );
  });
});
